#!/bin/bash

echo "🚀 Démarrage de l'application GegeDot"
echo ""

# Vérifier Docker
if ! docker info > /dev/null 2>&1; then
    echo "❌ Docker n'est pas démarré. Veuillez démarrer Docker Desktop."
    exit 1
fi

echo "✅ Docker est démarré"
echo ""

# Démarrer MySQL et Backend
echo "📦 Démarrage des containers (MySQL et Backend)..."
docker-compose up -d mysql backend

echo ""
echo "⏳ Attente 5 secondes que les services démarrent..."
sleep 5

# Vérifier le backend
echo ""
echo "🔍 Vérification du backend..."
if curl -s http://localhost:5000/api/persons > /dev/null 2>&1; then
    echo "✅ Backend accessible sur http://localhost:5000"
else
    echo "⚠️  Le backend ne répond pas encore. Vérifiez avec: docker logs gegeDot-backend"
fi

# Démarrer le serveur frontend
echo ""
echo "🌐 Démarrage du serveur frontend sur le port 3004..."
cd frontend

if lsof -Pi :3004 -sTCP:LISTEN -t >/dev/null 2>&1; then
    echo "⚠️  Le port 3004 est déjà utilisé."
    echo "   Pour arrêter: lsof -ti:3004 | xargs kill"
    echo ""
    echo "✅ Application accessible sur: http://localhost:3004/professional-fan-view.html"
else
    echo "✅ Serveur démarré!"
